class SecureLoggingSystem private constructor(private val context: Context) {

    private val gson: Gson = GsonBuilder().setPrettyPrinting().create()
    private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
    private val logFile: File by lazy {
        File(context.filesDir, "app_logs.txt")
    }

    companion object {
        @Volatile
        private var instance: SecureLoggingSystem? = null

        fun initialize(context: Context, isDebugBuild: Boolean) {
            if (instance == null) {
                synchronized(this) {
                    if (instance == null) {
                        instance = SecureLoggingSystem(context.applicationContext)
                        setupTimber(isDebugBuild)
                    }
                }
            }
        }

        fun getInstance(): SecureLoggingSystem {
            return instance ?: throw IllegalStateException("SecureLoggingSystem not initialized")
        }

        private fun setupTimber(isDebugBuild: Boolean) {
            Timber.uprootAll()
            if (isDebugBuild) {
                Timber.plant(Timber.DebugTree())
            }
            Timber.plant(ProductionTree())
        }

        private val SENSITIVE_KEYS = setOf(
            "password", "passwd", "pwd", "secret", "token", "auth", "authorization",
            "api_key", "apikey", "access_token", "refresh_token", "session", "cookie",
            "credit_card", "creditcard", "cvv", "ssn", "pin", "private_key", "privatekey",
            "bearer", "jwt", "oauth", "key", "credentials", "credential"
        )

        private val SENSITIVE_HEADERS = setOf(
            "authorization", "cookie", "set-cookie", "x-api-key", "x-auth-token",
            "x-access-token", "x-refresh-token", "proxy-authorization"
        )
    }

    private class ProductionTree : Timber.Tree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            if (priority >= Log.INFO) {
                val sanitizedMessage = sanitizeMessage(message)
                when (priority) {
                    Log.ERROR -> Log.e(tag ?: "App", sanitizedMessage, t)
                    Log.WARN -> Log.w(tag ?: "App", sanitizedMessage)
                    Log.INFO -> Log.i(tag ?: "App", sanitizedMessage)
                }
            }
        }

        private fun sanitizeMessage(message: String): String {
            var sanitized = message
            SENSITIVE_KEYS.forEach { key ->
                val regex = Regex("($key[\"']?\\s*[:=]\\s*[\"']?)([^,\\s\"'}\\]]+)", RegexOption.IGNORE_CASE)
                sanitized = sanitized.replace(regex, "$1[REDACTED]")
            }
            return sanitized
        }
    }

    fun logAuthenticationAttempt(
        username: String?,
        success: Boolean,
        failureReason: String? = null,
        metadata: Map<String, Any>? = null
    ) {
        val sanitizedUsername = username?.let { maskSensitiveData(it) } ?: "unknown"
        val status = if (success) "SUCCESS" else "FAILED"
        val reason = failureReason?.let { " - Reason: $it" } ?: ""
        val meta = metadata?.let { sanitizeMap(it) }?.let { " - Metadata: $it" } ?: ""

        val logMessage = "AUTH_ATTEMPT: User=$sanitizedUsername, Status=$status$reason$meta"

        if (success) {
            Timber.i(logMessage)
        } else {
            Timber.w(logMessage)
        }

        writeToFile("AUTH", logMessage)
    }

    fun logDatabaseQuery(
        query: String,
        parameters: List<Any?>? = null,
        executionTimeMs: Long? = null,
        rowsAffected: Int? = null
    ) {
        val sanitizedQuery = sanitizeQuery(query)
        val sanitizedParams = parameters?.map { sanitizeParameter(it) }
        val timing = executionTimeMs?.let { " - ExecutionTime: ${it}ms" } ?: ""
        val rows = rowsAffected?.let { " - RowsAffected: $it" } ?: ""

        val logMessage = "DB_QUERY: $sanitizedQuery - Params: $sanitizedParams$timing$rows"

        Timber.d(logMessage)
        writeToFile("DATABASE", logMessage)
    }

    fun logApiRequest(
        method: String,
        url: String,
        headers: Map<String, String>?,
        body: String?,
        responseCode: Int? = null,
        responseBody: String? = null,
        durationMs: Long? = null
    ) {
        val sanitizedUrl = sanitizeUrl(url)
        val sanitizedHeaders = headers?.let { sanitizeHeaders(it) }
        val sanitizedRequestBody = body?.let { sanitizeBody(it) }
        val sanitizedResponseBody = responseBody?.let { sanitizeBody(it) }

        val requestLog = buildString {
            append("API_REQUEST: $method $sanitizedUrl")
            sanitizedHeaders?.let { append("\nHeaders: $it") }
            sanitizedRequestBody?.let { append("\nBody: $it") }
        }

        Timber.i(requestLog)
        writeToFile("API_REQUEST", requestLog)

        if (responseCode != null) {
            val responseLog = buildString {
                append("API_RESPONSE: $method $sanitizedUrl - Status: $responseCode")
                durationMs?.let { append(" - Duration: ${it}ms") }
                sanitizedResponseBody?.let { append("\nBody: $it") }
            }

            if (responseCode >= 400) {
                Timber.w(responseLog)
            } else {
                Timber.i(responseLog)
            }
            writeToFile("API_RESPONSE", responseLog)
        }
    }

    fun logException(
        exception: Throwable,
        context: String? = null,
        additionalInfo: Map<String, Any>? = null
    ) {
        val sanitizedInfo = additionalInfo?.let { sanitizeMap(it) }
        val contextStr = context?.let { "Context: $it - " } ?: ""
        val infoStr = sanitizedInfo?.let { "Info: $it - " } ?: ""

        val logMessage = "EXCEPTION: ${contextStr}${infoStr}${exception.javaClass.simpleName}: ${exception.message}"

        Timber.e(exception, logMessage)

        val stackTrace = sanitizeStackTrace(exception)
        writeToFile("EXCEPTION", "$logMessage\n$stackTrace")
    }

    fun logUserAction(action: String, details: Map<String, Any>? = null) {
        val sanitizedDetails = details?.let { sanitizeMap(it) }
        val logMessage = "USER_ACTION: $action${sanitizedDetails?.let { " - $it" } ?: ""}"

        Timber.i(logMessage)
        writeToFile("USER_ACTION", logMessage)
    }

    private fun sanitizeQuery(query: String): String {
        var sanitized = query
        val patterns = listOf(
            Regex("(password|token|secret)\\s*=\\s*'[^']+'", RegexOption.IGNORE_CASE),
            Regex("(password|token|secret)\\s*=\\s*\"[^\"]+\"", RegexOption.IGNORE_CASE),
            Regex("(password|token|secret)\\s*=\\s*[^\\s,)]+", RegexOption.IGNORE_CASE)
        )

        patterns.forEach { pattern ->
            sanitized = sanitized.replace(pattern) { matchResult ->
                "${matchResult.groupValues[1]} = '[REDACTED]'"
            }
        }

        return sanitized
    }

    private fun sanitizeParameter(param: Any?): String {
        return when (param) {
            null -> "null"
            is String -> if (param.length > 100) "${param.take(100)}..." else param
            is Number -> param.toString()
            is Boolean -> param.toString()
            else -> param.javaClass.simpleName
        }
    }

    private fun sanitizeUrl(url: String): String {
        var sanitized = url
        val tokenPattern = Regex("([?&])(token|key|auth|api_key)=([^&]+)", RegexOption.IGNORE_CASE)
        sanitized = sanitized.replace(tokenPattern, "$1$2=[REDACTED]")
        return sanitized
    }

    private fun sanitizeHeaders(headers: Map<String, String>): Map<String, String> {
        return headers.mapValues { (key, value) ->
            if (SENSITIVE_HEADERS.contains(key.lowercase())) {
                "[REDACTED]"
            } else {
                value
            }
        }
    }

    private fun sanitizeBody(body: String): String {
        if (body.isBlank()) return body

        return try {
            val jsonElement = JsonParser.parseString(body)
            if (jsonElement.isJsonObject) {
                val jsonObject = jsonElement.asJsonObject
                sanitizeJsonObject(jsonObject)
                gson.toJson(jsonObject)
            } else {
                if (body.length > 500) "${body.take(500)}..." else body
            }
        } catch (e: Exception) {
            if (body.length > 500) "${body.take(500)}..." else body
        }
    }

    private fun sanitizeJsonObject(jsonObject: com.google.gson.JsonObject) {
        val keysToRedact = mutableListOf<String>()

        jsonObject.keySet().forEach { key ->
            if (SENSITIVE_KEYS.any { key.lowercase().contains(it) }) {
                keysToRedact.add(key)
            } else {
                val element = jsonObject.get(key)
                if (element.isJsonObject) {
                    sanitizeJsonObject(element.asJsonObject)
                } else if (element.isJsonArray) {
                    element.asJsonArray.forEach { item ->
                        if (item.isJsonObject) {
                            sanitizeJsonObject(item.asJsonObject)
                        }
                    }
                }
            }
        }

        keysToRedact.forEach { key ->
            jsonObject.addProperty(key, "[REDACTED]")
        }
    }

    private fun sanitizeMap(map: Map<String, Any>): Map<String, Any> {
        return map.mapValues { (key, value) ->
            if (SENSITIVE_KEYS.any { key.lowercase().contains(it) }) {
                "[REDACTED]"
            } else {
                when (value) {
                    is Map<*, *> -> sanitizeMap(value as Map<String, Any>)
                    is String -> if (value.length > 200) "${value.take(200)}..." else value
                    else -> value
                }
            }
        }
    }

    private fun maskSensitiveData(data: String): String {
        return if (data.length <= 4) {
            "***"
        } else {
            "${data.take(2)}***${data.takeLast(2)}"
        }
    }

    private fun sanitizeStackTrace(exception: Throwable): String {
        val stackTrace = StringBuilder()
        stackTrace.append("${exception.javaClass.name}: ${exception.message}\n")

        exception.stackTrace.take(10).forEach { element ->
            if (!element.className.contains("password", ignoreCase = true) &&
                !element.className.contains("credential", ignoreCase = true)) {
                stackTrace.append("  at ${element.className}.${element.methodName}(${element.fileName}:${element.lineNumber})\n")
            }
        }

        exception.cause?.let { cause ->
            stackTrace.append("Caused by: ${cause.javaClass.name}: ${cause.message}\n")
            cause.stackTrace.take(5).forEach { element ->
                stackTrace.append("  at ${element.className}.${element.methodName}(${element.fileName}:${element.lineNumber})\n")
            }
        }

        return stackTrace.toString()
    }

    private fun writeToFile(category: String, message: String) {
        try {
            val timestamp = dateFormat.format(Date())
            val logEntry = "[$timestamp] [$category] $message\n"

            FileWriter(logFile, true).use { writer ->
                writer.append(logEntry)
            }

            if (logFile.length() > 5 * 1024 * 1024) {
                rotateLogFile()
            }
        } catch (e: IOException) {
            Timber.e(e, "Failed to write to log file")
        }
    }

    private fun rotateLogFile() {
        try {
            val backupFile = File(context.filesDir, "app_logs_backup.txt")
            if (backupFile.exists()) {
                backupFile.delete()
            }
            logFile.renameTo(backupFile)
        } catch (e: Exception) {
            Timber.e(e, "Failed to rotate log file")
        }
    }

    fun getLogFile(): File = logFile

    fun clearLogs() {
        try {
            logFile.delete()
            Timber.i("Logs cleared")
        } catch (e: Exception) {
            Timber.e(e, "Failed to clear logs")
        }
    }
}

class SecureLoggingInterceptor : Interceptor {
    private val loggingSystem by lazy { SecureLoggingSystem.getInstance() }

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startTime = System.currentTimeMillis()

        val headers = request.headers.toMultimap().mapValues { it.value.joinToString(", ") }
        val requestBody = request.body?.let { body ->
            val buffer = Buffer()
            body.writeTo(buffer)
            buffer.readUtf8()
        }

        loggingSystem.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = headers,
            body = requestBody
        )

        val response: Response
        try {
            response = chain.proceed(request)
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            loggingSystem.logException(e, "API Request Failed: ${request.method} ${request.url}", mapOf(
                "duration" to duration
            ))
            throw e
        }

        val duration = System.currentTimeMillis() - startTime
        val responseBody = response.body?.let { body ->
            val source = body.source()
            source.request(Long.MAX_VALUE)
            source.buffer.clone().readUtf8()
        }

        loggingSystem.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = null,
            body = null,
            responseCode = response.code,
            responseBody = responseBody,
            durationMs = duration
        )

        return response
    }
}

object LoggingHelper {
    fun logAuthSuccess(username: String, metadata: Map<String, Any>? = null) {
        SecureLoggingSystem.getInstance().logAuthenticationAttempt(username, true, null, metadata)
    }

    fun logAuthFailure(username: String?, reason: String, metadata: Map<String, Any>? = null) {
        SecureLoggingSystem.getInstance().logAuthenticationAttempt(username, false, reason, metadata)
    }

    fun logDbQuery(query: String, params: List<Any?>? = null, timeMs: Long? = null, rows: Int? = null) {
        SecureLoggingSystem.getInstance().logDatabaseQuery(query, params, timeMs, rows)
    }

    fun logError(throwable: Throwable, context: String? = null, info: Map<String, Any>? = null) {
        SecureLoggingSystem.getInstance().logException(throwable, context, info)
    }

    fun logUserAction(action: String, details: Map<String, Any>? = null) {
        SecureLoggingSystem.getInstance().logUserAction(action, details)
    }
}